async function getTokenInfo(accessToken) {
    const payload = await jwt.verify(accessToken, process.env['TOKEN_KEY'], {algorithms: ["HS256"]}); // we're using HS256 (hmac with sha 256). It's assumed that the private key is stored in an environment variable called TOKEN_KEY

    return payload
}

